/**
 * NBD — Visualizer Image Generation (Gemini 2.5 Flash Image)
 * ═══════════════════════════════════════════════════════════════
 *
 * Replaces the old canvas color-filter "visualization" with a real
 * AI-edited image of the user's home, generated by Google Gemini
 * 2.5 Flash Image (aka "Nano Banana"). ~$0.02-$0.04 per call.
 *
 * The Claude-based text analysis (publicVisualizerAI in index.js)
 * stays — it returns Joe's written assessment. This function
 * returns the edited JPEG image. The frontend calls both in
 * parallel, then renders the image + text side-by-side.
 *
 * Safety:
 *   - Gated by FUNNEL_RECOVERY-style env flag VISUALIZER_IMAGEGEN_ENABLED
 *     (default OFF). When disabled, returns 503 and the frontend
 *     falls back to the existing canvas color filter.
 *   - Tighter rate limit than text endpoint: 3/hour per IP (image
 *     generation is more expensive).
 *   - App Check inherited from existing CORS + rate-limit pattern.
 */

const { onRequest } = require('firebase-functions/v2/https');
const { defineSecret } = require('firebase-functions/params');
const { logger } = require('firebase-functions/v2');

// Shared with other functions — re-use the same rate limiter
const { httpRateLimit } = require('./rate-limit');

// ───────────────────────────────────────────────────────────────
// Config
// ───────────────────────────────────────────────────────────────

const GOOGLE_AI_API_KEY = defineSecret('GOOGLE_AI_API_KEY');

const CORS_ORIGINS = [
  'https://nobigdealwithjoedeal.com',
  'https://nobigdeal-pro.web.app',
];

// Model endpoint (stable URL; model ID is the alias "gemini-2.5-flash-image")
const GEMINI_MODEL = 'gemini-2.5-flash-image';
const GEMINI_ENDPOINT =
  'https://generativelanguage.googleapis.com/v1beta/models/' +
  GEMINI_MODEL +
  ':generateContent';

// Max input image — match the text endpoint's cap so the frontend can
// use one resize path for both requests.
const MAX_B64_BYTES = 1_500_000; // ~1.1 MB raw before base64 inflation

// Prompt fragments for each material/style option. Kept as a dict so
// unknown selections fall back cleanly instead of leaking raw tile IDs
// into the prompt.

const ROOF_STYLE_LABELS = {
  architectural: 'architectural dimensional shingles',
  '3-tab': 'traditional 3-tab shingles',
  luxury: 'luxury designer shingles',
  metal: 'standing-seam metal roofing',
  slate: 'slate tile roofing',
};

const ROOF_COLOR_LABELS = {
  charcoal: 'charcoal black-gray',
  'weathered-wood': 'weathered-wood warm brown',
  driftwood: 'driftwood tan',
  onyx: 'deep onyx black',
  sand: 'sand beige',
  pewter: 'pewter gray',
  'rustic-red': 'rustic barn red',
  'hunter-green': 'hunter green',
};

const SIDING_STYLE_LABELS = {
  'dutch-lap': 'dutch-lap vinyl siding',
  'board-batten': 'board-and-batten vertical siding',
  shake: 'cedar-shake-style siding',
  horizontal: 'horizontal lap siding',
  'fiber-cement': 'James Hardie fiber-cement siding',
};

const SIDING_COLOR_LABELS = {
  cream: 'warm cream',
  linen: 'soft linen white',
  'slate-gray': 'slate gray',
  'charcoal-blue': 'charcoal blue-gray',
  navy: 'deep navy blue',
  cedar: 'cedar brown',
  forest: 'forest green',
  black: 'matte black',
};

const GUTTER_COLOR_LABELS = {
  white: 'crisp white',
  bronze: 'dark bronze',
  black: 'matte black',
  brown: 'warm brown',
  'match-trim': 'a color matching the trim',
};

function sanitizeString(value, maxLen = 400) {
  if (typeof value !== 'string') return '';
  return value.trim().slice(0, maxLen);
}

function buildPrompt(selections) {
  const parts = [];

  if (selections.features.includes('roof')) {
    const style = ROOF_STYLE_LABELS[selections.roofStyle] || 'architectural shingles';
    const color = ROOF_COLOR_LABELS[selections.roofColor] || selections.roofColor || 'charcoal';
    parts.push(`Replace the roof with ${style} in ${color}. Keep the roof shape, pitch, and every architectural detail identical — only change the shingle material and color.`);
  }

  if (selections.features.includes('siding')) {
    const style = SIDING_STYLE_LABELS[selections.sidingStyle] || 'horizontal lap siding';
    const color = SIDING_COLOR_LABELS[selections.sidingColor] || selections.sidingColor || 'cream';
    parts.push(`Replace the siding with ${style} in ${color}. Keep every window, door, trim line, porch railing, and architectural detail identical — only change the siding material and color.`);
  }

  if (selections.features.includes('gutters')) {
    const color = GUTTER_COLOR_LABELS[selections.gutterColor] || selections.gutterColor || 'white';
    parts.push(`Replace the gutters and downspouts with seamless K-style in ${color}.`);
  }

  if (selections.features.includes('windows')) parts.push('Subtly refresh the window frames (clean, modern, same size and placement).');
  if (selections.features.includes('garage')) parts.push('Update the garage door to a modern paneled design (same size and position).');
  if (selections.features.includes('shutters')) parts.push('Add or refresh exterior shutters that match the trim color.');
  if (selections.features.includes('doors')) parts.push('Freshen the front door with a color that complements the new exterior.');

  if (!parts.length) parts.push('Leave the home essentially unchanged; just clean up and color-correct the image.');

  const notes = sanitizeString(selections.notes, 300);
  if (notes) parts.push(`Additional notes from the homeowner: ${notes}`);

  // System-style instructions to keep the model on-task
  const guardrails = [
    'This is a real homeowner\'s property — be photorealistic and accurate.',
    'Do NOT change the house shape, the landscaping, the sky, the ground, neighboring properties, vehicles, or any people.',
    'Preserve the original photo\'s perspective, lighting direction, and shadow angles.',
    'Do not add text, watermarks, logos, or signage.',
    'Output a single photorealistic JPEG image. No commentary, no bullet list, just the edited photo.',
  ];

  return parts.join(' ') + '\n\n' + guardrails.join(' ');
}

// ───────────────────────────────────────────────────────────────
// visualizerImageGen — HTTP endpoint
// ───────────────────────────────────────────────────────────────
//
// Request body:
//   {
//     imageBase64:  string (required, raw b64 no data-URL prefix),
//     mediaType:    'image/jpeg' | 'image/png' | 'image/webp',
//     features:     string[],  // ['roof','siding','gutters','windows','garage','shutters','doors']
//     roofStyle:    string,
//     roofColor:    string,
//     sidingStyle:  string,
//     sidingColor:  string,
//     gutterColor:  string,
//     notes?:       string
//   }
//
// Response (success):
//   { imageBase64: string, mediaType: 'image/png' }
//
// Response (error):
//   { error: 'descriptive_token' }  — HTTP 400 | 413 | 429 | 503 | 500

exports.visualizerImageGen = onRequest(
  {
    cors: CORS_ORIGINS,
    secrets: [GOOGLE_AI_API_KEY],
    maxInstances: 5,
    concurrency: 10,
    timeoutSeconds: 60,
    memory: '256MiB',
  },
  async (req, res) => {
    if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
    if (req.method !== 'POST') {
      res.status(405).json({ error: 'method_not_allowed' });
      return;
    }

    // Feature flag — keeps this off until Joe confirms quality + cost
    if (process.env.VISUALIZER_IMAGEGEN_ENABLED !== 'true') {
      res.status(503).json({ error: 'disabled' });
      return;
    }

    // Tight rate limit — image gen is ~5x the cost of the text endpoint,
    // so 3/hour/IP caps each abuser at ~$0.12/hour.
    if (!(await httpRateLimit(req, res, 'visualizerImageGen:ip', 3, 3_600_000))) return;

    try {
      const body = req.body || {};
      const imageBase64 = sanitizeString(body.imageBase64, MAX_B64_BYTES * 2);
      if (!imageBase64 || imageBase64.length === 0) {
        res.status(400).json({ error: 'imageBase64 required' });
        return;
      }
      if (imageBase64.length > MAX_B64_BYTES) {
        res.status(413).json({ error: 'image_too_large' });
        return;
      }

      const allowedMedia = new Set(['image/jpeg', 'image/png', 'image/webp']);
      const mediaType = allowedMedia.has(body.mediaType) ? body.mediaType : 'image/jpeg';

      const selections = {
        features: Array.isArray(body.features) ? body.features.slice(0, 10).map((s) => sanitizeString(s, 40)) : ['roof'],
        roofStyle:   sanitizeString(body.roofStyle, 40),
        roofColor:   sanitizeString(body.roofColor, 40),
        sidingStyle: sanitizeString(body.sidingStyle, 40),
        sidingColor: sanitizeString(body.sidingColor, 40),
        gutterColor: sanitizeString(body.gutterColor, 40),
        notes:       sanitizeString(body.notes, 300),
      };

      const prompt = buildPrompt(selections);

      const geminiBody = {
        contents: [{
          parts: [
            { text: prompt },
            { inline_data: { mime_type: mediaType, data: imageBase64 } },
          ],
        }],
        // Gemini 2.5 Flash Image requires BOTH text and image modalities —
        // image-only is rejected. The response always includes an image part
        // and we drop the text part server-side so the client never sees it.
        generationConfig: {
          responseModalities: ['TEXT', 'IMAGE'],
        },
      };

      const response = await fetch(GEMINI_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-goog-api-key': GOOGLE_AI_API_KEY.value(),
        },
        body: JSON.stringify(geminiBody),
      });

      if (!response.ok) {
        const errText = await response.text().catch(() => '');
        // Log full upstream body so we can diagnose from Firebase logs.
        // Never echoes this to the client — stays in Cloud Logging only.
        logger.warn('visualizerImageGen: upstream error', {
          status: response.status,
          body: errText.slice(0, 2000),
        });
        // Echo the upstream status as a machine-parseable hint. Client only
        // sees 'upstream_error' text so no internal details leak to users.
        res.status(502).json({ error: 'upstream_error', upstream_status: response.status });
        return;
      }

      const data = await response.json();

      // Find the image part in the response (Gemini nests under candidates[0].content.parts[])
      const parts =
        (data.candidates && data.candidates[0] && data.candidates[0].content && data.candidates[0].content.parts) ||
        [];

      let outImage = null;
      let outMediaType = 'image/png';
      for (const p of parts) {
        const inline = p.inline_data || p.inlineData; // REST + SDK naming drift
        if (inline && inline.data) {
          outImage = inline.data;
          outMediaType = inline.mime_type || inline.mimeType || 'image/png';
          break;
        }
      }

      if (!outImage) {
        logger.warn('visualizerImageGen: no image in response', { keys: Object.keys(data) });
        res.status(502).json({ error: 'no_image_returned' });
        return;
      }

      res.json({ imageBase64: outImage, mediaType: outMediaType });
    } catch (e) {
      logger.error('visualizerImageGen error', { err: e && e.message });
      res.status(500).json({ error: 'server_error' });
    }
  }
);
